using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Zona de "fora da área" / hazard fatal para inimigos (Enemy Creator — Etapa
/// 8.2; GDD 12.1: neutralizar = destruir/desligar/prender OU empurrar para
/// fora da área).
///
/// Collider2D (trigger) colocado em abismos, lava, água profunda, bordas da
/// arena, etc. Quando um inimigo entra (ex: empurrado por knockback —
/// EnemyHealth.ApplyKnockback com weaknesses.canBePushed), é neutralizado:
/// Morre (via EnemyHealth.Kill — dispara drops/feedback/persistência) ou
/// Desactiva, conforme "reaction".
///
/// "onlyPushable" restringe a inimigos com canBePushed (zonas pensadas só
/// para a mecânica de empurrar); desligado, neutraliza qualquer inimigo que
/// caia lá dentro.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class EnemyVoidTrigger : MonoBehaviour
{
    [Tooltip("O que acontece ao inimigo que entra na zona.")]
    public EnemyWaterReaction reaction = EnemyWaterReaction.Morre;

    [Tooltip("Só afecta inimigos com 'canBePushed' (zonas da mecânica de empurrar). Desligado = afecta qualquer inimigo.")]
    public bool onlyPushable = false;

    [Tooltip("Inimigos que recebem dano de hazards ('canTakeDamageFromHazards' desligado) ficam imunes a esta zona? Liga para tratar a zona como hazard normal.")]
    public bool respectHazardImmunity = false;

    [Tooltip("Disparado quando um inimigo é neutralizado por esta zona.")]
    public UnityEvent<EnemyController> onEnemyNeutralized;

    private void Awake()
    {
        var col = GetComponent<Collider2D>();
        if (!col.isTrigger)
            Debug.LogWarning($"[{name}] O Collider2D do EnemyVoidTrigger deve ser 'Is Trigger'.", this);
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        var enemy = other.GetComponent<EnemyController>();
        if (enemy == null || enemy.IsTerminal) return;

        var weaknesses = enemy.Data != null ? enemy.Data.weaknesses : null;

        if (onlyPushable && (weaknesses == null || !weaknesses.canBePushed)) return;
        if (respectHazardImmunity && weaknesses != null && !weaknesses.canTakeDamageFromHazards) return;

        switch (reaction)
        {
            case EnemyWaterReaction.Morre:
                var health = enemy.GetEnemyComponent<EnemyHealth>();
                if (health != null) health.Kill();
                else enemy.SetState(EnemyState.Morto);
                break;

            case EnemyWaterReaction.Desactiva:
                enemy.SetState(EnemyState.Desactivado);
                break;

            default:
                return; // Nenhuma: zona configurada como inerte
        }

        onEnemyNeutralized?.Invoke(enemy);
    }
}
